from sympy import legendre_symbol, primerange
def check(p):
    N, a, b = [], 2, 1
    while True:
        N.append(legendre_symbol(a, p))
        a, b = b, (a + b) % p
        if (a, b) == (2, 1): break
    return N.count(1) == N.count(-1) + N.count(0)
print([p for p in primerange(3, 3000) if check(p)])

